    function shell_run($command, $timeout = null, $cwd = null)
    {
        $raw_command = isset($command) ? trim($command) : '';
        if ($raw_command === '') {
            return ['error' => 'Command is required.', 'exit_code' => -1, 'stdout' => '', 'stderr' => ''];
        }

        $timeout = isset($timeout) ? max(1, min(15, (int)$timeout)) : 10;
        $cwd = isset($cwd) ? trim($cwd) : '';
        $project_root = getcwd();

        // --- Safety: whitelist allowed commands ---
        $allowed_cmds = [
            'php' => true,       // php -v, php -l, php -r, php -i, php -m
            'composer' => true,  // composer show, composer why
            'git' => true,       // git log, git status, git diff --stat (read-only git ops only)
            'cat' => true,       // cat files (project only)
            'echo' => true,      // echo
            'pwd' => true,       // pwd
            'ls' => true,        // ls
            'which' => true,     // which
            'head' => true,      // head
            'tail' => true,      // tail
            'wc' => true,        // wc
        ];

        // Parse the base command
        $parts = preg_split('/\s+/', $raw_command);
        $base_cmd = $parts[0] ?? '';

        if (!isset($allowed_cmds[$base_cmd])) {
            return [
                'error' => "Command '$base_cmd' is not in the allowed whitelist. Allowed: " . implode(', ', array_keys($allowed_cmds)),
                'exit_code' => -1, 'stdout' => '', 'stderr' => '',
            ];
        }

        // --- Safety: block dangerous git operations ---
        if ($base_cmd === 'git') {
            $dangerous_git = ['push', 'pull', 'commit', 'merge', 'rebase', 'reset', 'checkout', 'branch -d', 'branch -D', 'tag', 'rm', 'mv', 'add', 'fetch', 'cherry-pick', 'revert'];
            $full_lower = strtolower($raw_command);
            foreach ($dangerous_git as $danger) {
                if (str_contains($full_lower, $danger)) {
                    return [
                        'error' => "Dangerous git operation '$danger' is blocked. Only read-only git commands allowed (log, status, diff, show, describe, shortlog).",
                        'exit_code' => -1, 'stdout' => '', 'stderr' => '',
                    ];
                }
            }
        }

        // --- Safety: block shell metacharacters ---
        // No piping, redirection, command substitution, chaining
        $dangerous_chars = ['|', '>', '<', ';', '&', '`', '$('];
        foreach ($dangerous_chars as $char) {
            if (str_contains($raw_command, $char)) {
                return [
                    'error' => "Shell metacharacter '$char' is blocked for safety.",
                    'exit_code' => -1, 'stdout' => '', 'stderr' => '',
                ];
            }
        }

        // --- Safety: block absolute paths outside project ---
        if (str_contains($raw_command, '/etc/') || str_contains($raw_command, '/usr/') || str_contains($raw_command, '/var/') || str_contains($raw_command, '/tmp/') || str_contains($raw_command, '/bin/') || str_contains($raw_command, '/sbin/') || str_contains($raw_command, '/dev/') || str_contains($raw_command, '/proc/') || str_contains($raw_command, '/sys/') || str_contains($raw_command, '/root/') || str_contains($raw_command, '/home/')) {
            return [
                'error' => 'Access to system directories outside the project is blocked.',
                'exit_code' => -1, 'stdout' => '', 'stderr' => '',
            ];
        }

        // --- Safety: resolve working directory ---
        $full_cwd = $project_root;
        if ($cwd !== '') {
            $full_cwd = $project_root . '/' . ltrim($cwd, '/');
            $real_cwd = realpath($full_cwd);
            $real_root = realpath($project_root);
            if ($real_cwd === false || $real_root === false || strpos($real_cwd, $real_root) !== 0) {
                return [
                    'error' => "Working directory '$cwd' is outside the project root.",
                    'exit_code' => -1, 'stdout' => '', 'stderr' => '',
                ];
            }
            $full_cwd = $real_cwd;
        }

        // --- Execute via proc_open ---
        $descriptorspec = [
            0 => ['pipe', 'r'],  // stdin
            1 => ['pipe', 'w'],  // stdout
            2 => ['pipe', 'w'],  // stderr
        ];

        $process = proc_open($raw_command, $descriptorspec, $pipes, $full_cwd);

        if (!is_resource($process)) {
            return [
                'error' => 'Failed to start subprocess.',
                'exit_code' => -1, 'stdout' => '', 'stderr' => '',
            ];
        }

        fclose($pipes[0]); // Close stdin immediately

        $stdout = '';
        $stderr = '';
        $start_time = time();
        $timed_out = false;

        // Set non-blocking mode
        stream_set_blocking($pipes[1], false);
        stream_set_blocking($pipes[2], false);

        // Read output with timeout
        while (true) {
            $read = [$pipes[1], $pipes[2]];
            $write = null;
            $except = null;
            
            if (stream_select($read, $write, $except, 1) > 0) {
                foreach ($read as $r) {
                    $chunk = fread($r, 8192);
                    if ($chunk !== false && $chunk !== '') {
                        if ($r === $pipes[1]) $stdout .= $chunk;
                        if ($r === $pipes[2]) $stderr .= $chunk;
                    }
                }
            }
            
            // Check if process is still running
            $status = proc_get_status($process);
            if ($status === false) break;
            if (!$status['running']) {
                // Read any remaining output
                $remaining_out = stream_get_contents($pipes[1]);
                $remaining_err = stream_get_contents($pipes[2]);
                if ($remaining_out !== false) $stdout .= $remaining_out;
                if ($remaining_err !== false) $stderr .= $remaining_err;
                break;
            }
            
            if ((time() - $start_time) > $timeout) {
                $timed_out = true;
                break;
            }
        }

        fclose($pipes[1]);
        fclose($pipes[2]);

        if ($timed_out) {
            proc_terminate($process, 9); // SIGKILL
            proc_close($process);
            return [
                'error' => "Command timed out after {$timeout}s.",
                'exit_code' => -1,
                'stdout' => $stdout,
                'stderr' => $stderr,
                'timed_out' => true,
            ];
        }

        $exit_code = proc_close($process);

        // Truncate output if too large
        $max_output = 50000;
        if (strlen($stdout) > $max_output) {
            $stdout = substr($stdout, 0, $max_output) . "\n[... truncated at {$max_output} chars ...]";
        }
